INSERT INTO `x2_cert` VALUES (1, '会计资格证', 'files/attach/images/content/20231130/17013135507819.png', 'storage/attach/public/20260621/2afbc55275efc60b59e869ea7eac6e71.jpg', 180, 1506817500, 'storage/attach/public/20260416/4c048ccfd04945c2da6a2aa6b03acde3.jpg', 'txt,140,350,{username},25\r\ntxt,700,350,会计资格证,25\r\ntxt,594,660,{ceqtime},25', '会计资格证', '<p>&lt;p&gt;1.学习完课程&lt;/p&gt;<br></p><p><br></p><p>&lt;p&gt;2.通过考试&lt;/p&gt;</p>');
INSERT INTO `x2_cert` VALUES (6, '初级会计证书', '', 'storage/attach/public/20260621/2cec53a203ffabfe668e332c8674c6b7.jpg', 365, 0, 'storage/attach/public/20260625/4ea96d0753adc90da1c6b1e4b6b92f90.jpg', 'txt,300,250,张三,24', '会计资格证是中国会计专业技术人员的职业资格证书，分为初级、中级和高级三个等级，通过全国统一考试获得。', '<h2>证书简介</h2><p>证书的说明</p><h2>获证条件</h2><p>获证条件</p><h2>发证机关</h2><p>获证条件</p>');

