INSERT INTO `x2_content` VALUES (7, 26, 35, 1, 'peadmin', '', '考试通知', 'tags', '关键字', 'storage/attach/public/20260622/c64da03b9011e16dc3710cb58136738d.jpg', '', 1581913227, 1782142090, 0, '摘要', '', 1, 'content_default', '<p style=\"text-indent: 2em; line-height: 2;\"><br></p><p style=\"text-align: start;\"><strong>【中关村在线原创技术】</strong>启境 GT7 将于 6 月 26 日正式上市。作为广汽集团与华为乾崑联合打造的高端智能新能源品牌，启境将深度融合华为乾崑全栈智能技术。渠道布局方面，启境 GT7 的销售网络将覆盖全国 70 座城市共 300 家门店，计划于 6 月底全部投入运营；门店采用双渠道模式，分为华为乾崑智驾授权体验中心与启境用户中心，分别承担体验展示与用户服务职能。</p><p style=\"text-align: start;\"><br></p><p style=\"text-align: center; line-height: 3;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26eky8.img?w=768&amp;h=512&amp;m=6\" alt=\"华为全栈自研 6月22日上市的启境 究竟有什么黑科技？\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: center; line-height: 3;\"><br></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">华为全栈自研 6月22日上市的启境 究竟有什么黑科技？</span><span style=\"color: rgb(112, 112, 112);\">© 中关村在线</span></p><p style=\"text-align: start;\">启境 GT7 延续了猎装车的低趴运动姿态，前脸采用封闭式格栅设计，搭配启境灵眸大灯组，运动氛围鲜明。官方信息显示，该大灯组由双横向日行灯与飞机造型小蓝灯构成，内部搭载华为 XPIXEL 百万像素智慧投影大灯，支持大屏投影、自定义绘图功能，兼顾基础照明与个性化表达。</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26eTiQ.img?w=768&amp;h=512&amp;m=6\" alt=\"华为全栈自研 6月22日上市的启境 究竟有什么黑科技？\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">华为全栈自研 6月22日上市的启境 究竟有什么黑科技？</span><span style=\"color: rgb(112, 112, 112);\">© 中关村在线</span></p><p style=\"text-align: start;\">此外，新车配备宽度达 1995mm 的蚌式铝合金前舱盖，内部预留前备厢空间，进一步拓展储物能力。车侧通过丰富的形面变化塑造出饱满的光影效果，尾部则搭载启境之翼尾灯，由 526 颗光源组成，采用分段式漫反射设计，呈现光影瀑布的视觉效果；同时尾灯融合 ADS 提示灯，打造全球首创 ADS 瀑布式蓝灯，支持迎宾展翼、驻车呼吸、光影谢幕等多场景定制动效。</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26eM3Q.img?w=768&amp;h=512&amp;m=6\" alt=\"华为全栈自研 6月22日上市的启境 究竟有什么黑科技？\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">华为全栈自研 6月22日上市的启境 究竟有什么黑科技？</span><span style=\"color: rgb(112, 112, 112);\">© 中关村在线</span></p><p style=\"text-align: start;\">车身尺寸方面，新车长宽高分别为 5050/1980/1470mm，轴距达到 3000mm，定位中大型猎装车。</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26ewIm.img?w=768&amp;h=512&amp;m=6\" alt=\"华为全栈自研 6月22日上市的启境 究竟有什么黑科技？\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">华为全栈自研 6月22日上市的启境 究竟有什么黑科技？</span><span style=\"color: rgb(112, 112, 112);\">© 中关村在线</span></p><p style=\"text-align: start;\">智能驾驶是新车的核心亮点，启境 GT7 首批搭载华为乾崑智驾 ADS 5 系统，硬件层面预埋 L3 级智能驾驶架构，配备目前全球量产最高规格的 896 线双光路图像级激光雷达，辅以 11 个高清摄像头、5 个毫米波雷达与 12 个超声波雷达，感知硬件规格拉满。目前，该车已获得广州市 L3 级自动驾驶道路测试许可。</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26ekyc.img?w=768&amp;h=512&amp;m=6\" alt=\"华为全栈自研 6月22日上市的启境 究竟有什么黑科技？\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">华为全栈自研 6月22日上市的启境 究竟有什么黑科技？</span><span style=\"color: rgb(112, 112, 112);\">© 中关村在线</span></p><p style=\"text-align: start;\">内饰采用环抱式座舱设计，搭载鸿蒙座舱 HarmonySpace 6，车内配备 15.6 英寸悬浮式中控屏、8.88 英寸窄条幅液晶仪表，以及 88 英寸增强现实抬头显示系统，科技氛围浓郁。</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26eEAd.img?w=768&amp;h=512&amp;m=6\" alt=\"华为全栈自研 6月22日上市的启境 究竟有什么黑科技？\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">华为全栈自研 6月22日上市的启境 究竟有什么黑科技？</span><span style=\"color: rgb(112, 112, 112);\">© 中关村在线</span></p><p style=\"text-align: start;\">舒适性配置方面，新车采用四门无框车门搭配双层夹胶玻璃，车顶配备三层银镀膜天幕，并搭载全新一代 PDLC 分区调光技术。内饰提供逐日红、星宇黑、月光米三种配色可选，覆盖不同审美需求。</p><p style=\"text-align: start;\">动力与底盘：800V 平台 + 全系空悬，最高续航 900km</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26f30c.img?w=768&amp;h=512&amp;m=6\" alt=\"华为全栈自研 6月22日上市的启境 究竟有什么黑科技？\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">华为全栈自研 6月22日上市的启境 究竟有什么黑科技？</span><span style=\"color: rgb(112, 112, 112);\">© 中关村在线</span></p><p style=\"text-align: start;\">动力层面，启境 GT7 基于 800V 高压平台打造，提供单电机与三电机两种动力版本，其中三电机版本 0-100km/h 加速仅需 2.98 秒。电池采用华为、宁德时代与启境三方联合定制的新一代麒麟电池，提供 86.111kWh 与 102.768kWh 两种容量，CLTC 工况最高续航里程可达 900km，同时支持 6C 超充能力。</p><p style=\"text-align: start;\">底盘方面，新车采用前双叉臂、后 H 臂多连杆悬架结构，全系标配闭式双腔空气悬架与连续阻尼可调减振器，兼顾操控性与乘坐舒适性。</p>', 91);

