DROP TABLE IF EXISTS `x2_course`;
CREATE TABLE `x2_course`  (
  `courseid` int NOT NULL AUTO_INCREMENT,
  `coursetitle` varchar(240) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `coursemodule` varchar(24) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `coursecsid` int NULL DEFAULT NULL,
  `coursedirid` int NULL DEFAULT NULL,
  `coursethumb` varchar(240) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `courseuserid` int NULL DEFAULT NULL,
  `courseinputtime` int NULL DEFAULT NULL,
  `coursemodifytime` int NULL DEFAULT NULL,
  `coursesequence` int NULL DEFAULT NULL,
  `coursedescribe` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL,
  `coursepath` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `coursepasstime` int NOT NULL,
  PRIMARY KEY (`courseid`) USING BTREE,
  INDEX `coursemodule`(`coursemodule`) USING BTREE,
  INDEX `coursecsid`(`coursecsid`) USING BTREE,
  INDEX `coursedirid`(`coursedirid`) USING BTREE,
  INDEX `coursesequence`(`coursesequence`) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 38 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

