INSERT INTO `x2_course` VALUES (35, '俞浩要求魔法原子抢宇树所有东西', 'md', 1, 1, 'storage/attach/public/20260414/8b775c025fc68248aca0bc6d32ff258f.png', 1, 1776155469, 1778411508, 0, '<p style=\"text-align: start;\">俞浩“发飙”了。4月10日，一张魔法原子内部群聊截图流出，截图显示俞浩一边批评宇树一边批评魔法原子团队。俞浩称，“宇树来抢我们的熊猫，抢签大佬。你们不仅是守，要去抢宇树的所有东西，宇树直播间去过的人全部抢过来签独家！包括每个主播，还有宇树的其他东西。”</p><p style=\"text-align: start;\">俞浩让团队抢宇树的所有客户、所有投标、所有员工，“要全部抢过来”！俞浩称团队现在“完全没有魄力，被动防守”，要求立即调整。</p><p style=\"text-align: start;\">此外，俞浩还表示要2亿年薪招首席科学家，“PR全部包围”。</p><p style=\"text-align: start;\">尽管俞浩要求上述内容不要截图外传，还是传了出来。</p><p style=\"text-align: start;\">魔法原子成立于2024年，是追觅科技孵化的机器人科技公司，专注于通用人形机器人和具身智能技术的研发与落地。</p>', '', 0);
INSERT INTO `x2_course` VALUES (36, '第一部曲', 'dir', 1, 1, 'storage/attach/public/20260414/08001da0113e4f8741806dd7946fbb1c.jpg', 1, 1776155519, 1778410755, 0, '<p style=\"text-align: start;\">俞浩“发飙”了。4月10日，一张魔法原子内部群聊截图流出，截图显示俞浩一边批评宇树一边批评魔法原子团队。俞浩称，“宇树来抢我们的熊猫，抢签大佬。你们不仅是守，要去抢宇树的所有东西，宇树直播间去过的人全部抢过来签独家！包括每个主播，还有宇树的其他东西。”</p><p style=\"text-align: start;\">俞浩让团队抢宇树的所有客户、所有投标、所有员工，“要全部抢过来”！俞浩称团队现在“完全没有魄力，被动防守”，要求立即调整。</p><p style=\"text-align: start;\">此外，俞浩还表示要2亿年薪招首席科学家，“PR全部包围”。</p><p style=\"text-align: start;\">尽管俞浩要求上述内容不要截图外传，还是传了出来。</p><p style=\"text-align: start;\">魔法原子成立于2024年，是追觅科技孵化的机器人科技公司，专注于通用人形机器人和具身智能技术的研发与落地。</p>', '', 0);
INSERT INTO `x2_course` VALUES (37, '二级目录子课件', 'html', 1, 36, 'storage/attach/public/20260414/69c29102123f7229b40d2db14b8722a4.jpg', 1, 1776155549, 1778410763, 0, '<p style=\"text-align: start;\">俞浩“发飙”了。4月10日，一张魔法原子内部群聊截图流出，截图显示俞浩一边批评宇树一边批评魔法原子团队。俞浩称，“宇树来抢我们的熊猫，抢签大佬。你们不仅是守，要去抢宇树的所有东西，宇树直播间去过的人全部抢过来签独家！包括每个主播，还有宇树的其他东西。”</p><p style=\"text-align: start;\">俞浩让团队抢宇树的所有客户、所有投标、所有员工，“要全部抢过来”！俞浩称团队现在“完全没有魄力，被动防守”，要求立即调整。</p><p style=\"text-align: start;\">此外，俞浩还表示要2亿年薪招首席科学家，“PR全部包围”。</p><p style=\"text-align: start;\">尽管俞浩要求上述内容不要截图外传，还是传了出来。</p><p style=\"text-align: start;\">魔法原子成立于2024年，是追觅科技孵化的机器人科技公司，专注于通用人形机器人和具身智能技术的研发与落地。</p>', '', 0);

