-- ----------------------------
INSERT INTO `x2_exam_basic` VALUES (1, '结业考试', 1, NULL, '{\"1\":[\"2\",\"1\",\"3\"]}', '{\"rulemodel\":0,\"model\":2,\"changesequence\":0,\"auto\":[\"3\",\"4\"],\"self\":[\"3\",\"4\",\"5\"],\"autotemplate\":\"1\",\"selftemplate\":\"0\",\"selectrule\":1,\"fullsubmit\":0,\"unjointime\":\"0\",\"examnumber\":\"0\",\"screennumber\":\"0\",\"notviewscore\":0}', 'storage/attach/public/20260620/e97c34ccaa37c4cdfbaf41ec8f6d8251.jpg', '本考场为PHPEMS系统演示考场', '<p style=\"text-align: start;\">现实中，现代存储设备靠电力维持数据，断电后最多几十年就变成无法读取的废物。全球数据中心堆积了海量冷数据，这些信息多年无人访问，却每天消耗巨额电力来降温和迁移。传统硬盘和磁带每隔五到十年就会出现故障，工程师不得不反复复制数据，这成了能源消耗的大头。</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA1ZqCZK.img?w=768&amp;h=416&amp;m=6\" alt=\"埋进土里一万年：为什么玻璃才是人类文明的“终极硬盘”？\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">埋进土里一万年：为什么玻璃才是人类文明的“终极硬盘”？</span></p><p style=\"text-align: start;\">数据中心里百分之六十以上的内容属于冷存储，却占用大量服务器资源。迁移过程不只费电，还需要人力和设备更新，长期看这直接影响国家算力分配。能源紧张的当下，谁能减少这种无谓开销，谁就能把更多电力留给人工智能计算。玻璃存储技术正好切中这个痛点，它一次写入后就不再需要供电，数据直接固化在材料内部。</p><p style=\"text-align: start;\">南安普顿大学光电子研究中心从二十多年前就开始研究这种5D存储。2024年9月，他们把完整人类基因组刻录进一块石英玻璃晶体里。整个过程用飞秒激光在玻璃内部形成纳米结构，这些结构像三维像素一样固定信息。晶体容量能达到数百TB，远超普通存储介质，而且耐高温和辐射。</p>');
INSERT INTO `x2_exam_basic` VALUES (38, 'Test1', 1, NULL, '{\"1\":[\"1\"]}', '{\"rulemodel\":0,\"model\":0,\"changesequence\":0,\"auto\":[\"3\",\"4\",\"5\"],\"autotemplate\":\"0\",\"self\":[\"3\",\"4\",\"5\"],\"selftemplate\":\"0\",\"selectrule\":1,\"fullsubmit\":0,\"unjointime\":\"0\",\"examnumber\":\"1\",\"screennumber\":\"0\",\"notviewscore\":0,\"opentime\":\"2026-05-13 16:51:49\",\"closetime\":\"2026-05-31 00:00:00\"}', 'storage/attach/public/20260620/3d594a7beaac426f3ccdaaf42b3eb1dc.jpg', 'Test2', '');
INSERT INTO `x2_exam_basic` VALUES (39, '历史基础', 2, NULL, '{\"4\":[\"5\"],\"5\":[]}', '{\"rulemodel\":0,\"model\":0,\"changesequence\":0,\"auto\":[\"6\",\"7\"],\"self\":[\"6\",\"7\"],\"autotemplate\":\"0\",\"selftemplate\":\"1\",\"selectrule\":0,\"fullsubmit\":0,\"unjointime\":\"0\",\"examnumber\":\"0\",\"screennumber\":\"0\",\"notviewscore\":0}', 'storage/attach/public/20260612/2913bee93e9919c8948478246a60b71d.jpg', '历史基础', '<p style=\"text-align: start;\">知名AMD爆料人Kepler_L2上直言：“<strong>要么Valve在这台机器上藏着丰厚的利润空间，要么他们就是被供应商狠狠宰了一笔</strong>。”另一位知名爆料者Moore\'s Law Is Dead则更倾向于前者，他在最新视频中指出，<strong>任何PC玩家都能用相同甚至更低的价格组装出一台性能强得多的电脑</strong>——这直接动摇了“供应链成本所迫”的解释。</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26riWo.img?w=768&amp;h=316&amp;m=6\" alt=\"AMD爆料人怒怼Steam Machine“千元神机” ：要么暴利 要么被供应商坑了\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">AMD爆料人怒怼Steam Machine“千元神机” ：要么暴利 要么被供应商坑了</span></p><p><br></p><p style=\"text-align: start;\">更让Valve尴尬的是，Digital Foundry的首批跑分显示，Steam Machine在大多数场景下甚至不敌2020年发售的PS5。而PS5即便经历两轮涨价，无光驱版目前仅售599.99美元，光驱版也不过649.99美元——分别比Steam Machine便宜了449美元和399美元。</p><p style=\"text-align: center;\"><img src=\"https://img-s.msn.cn/tenant/amp/entityid/AA26qMpU.img?w=768&amp;h=429&amp;m=6\" alt=\"AMD爆料人怒怼Steam Machine“千元神机” ：要么暴利 要么被供应商坑了\" data-href=\"\" style=\"width: auto !important;\"></p><p style=\"text-align: start;\"><span style=\"color: rgb(36, 36, 36);\">AMD爆料人怒怼Steam Machine“千元神机” ：要么暴利 要么被供应商坑了</span></p><p><br></p><p style=\"text-align: start;\">Steam Machine的高价是否预示PS6和下一代Xbox也将突破千美元大关?Ampere Analysis分析师Piers Harding-Rolls认为未必。他表示，索尼在供应链方面的议价能力和硬件规模都远强于Valve，且两年后组件供应状况会有所改善。不过他同时也提醒，次世代主机会搭载比Steam Machine昂贵得多的元件，即便索尼能拿到更好的供货协议，PS6最终售价依然可能不菲。</p>');

