INSERT INTO `x2_exam_history_detail` VALUES (58, 88, '{\"14\":\"10\",\"15\":\"10\",\"16\":\"10\",\"17\":\"10\",\"20\":\"10\",\"18\":20,\"21\":20}', '{\"totalScore\":100,\"totalTime\":10,\"passMark\":\"60.00\",\"questionTypeSort\":[1,2,6],\"scaleModel\":0,\"type\":2,\"questionTypes\":{\"1\":{\"number\":\"2\",\"score\":\"10\",\"describe\":\"\",\"easyNumber\":0,\"middleNumber\":0,\"hardNumber\":0},\"2\":{\"number\":\"2\",\"score\":\"10\",\"describe\":\"\",\"easyNumber\":0,\"middleNumber\":0,\"hardNumber\":0},\"6\":{\"number\":\"3\",\"score\":\"20\",\"describe\":\"\",\"easyNumber\":0,\"middleNumber\":0,\"hardNumber\":0}},\"questionScore\":{\"14\":\"10\",\"15\":\"10\",\"16\":\"10\",\"17\":\"10\",\"18\":\"25\",\"20\":\"10\",\"21\":\"25\"}}', '{\"1\":{\"questions\":[{\"questionid\":14,\"questiontype\":1,\"question\":\"<p>孔子是哪个学派的创始人<\\/p>\",\"questionhtml\":[\"佛\",\"道\",\"儒\",\"阴阳\"],\"questionlevel\":1,\"questionisparent\":0,\"questionanswer\":\"C\",\"points\":[5]},{\"questionid\":15,\"questiontype\":1,\"question\":\"<p>兵家创始人是<\\/p>\",\"questionhtml\":[\"孙膑\",\"孙武\",\"李靖\",\"韩信\"],\"questionlevel\":1,\"questionisparent\":0,\"questionanswer\":\"B\",\"points\":[5]}]},\"2\":{\"questions\":[{\"questionid\":16,\"questiontype\":2,\"question\":\"<p>孙子兵法中，风林火山的意思是什么？<\\/p>\",\"questionhtml\":[\"疾如风\",\"徐如林\",\"侵略如火\",\"不动如山\"],\"questionlevel\":1,\"questionisparent\":0,\"questionanswer\":\"ABCD\",\"points\":[5]},{\"questionid\":17,\"questiontype\":2,\"question\":\"<p>先秦儒家学派的代表人物有<\\/p>\",\"questionhtml\":[\"孟子\",\"庄子\",\"老子\",\"孔子\"],\"questionlevel\":1,\"questionisparent\":0,\"questionanswer\":\"AD\",\"points\":[5]}]},\"6\":{\"questions\":[{\"questionid\":18,\"questiontype\":6,\"question\":\"<p>简述秦始皇统一六国的历史意义<\\/p>\",\"questionhtml\":null,\"questionlevel\":1,\"questionisparent\":0,\"questionanswer\":\"<p><span style=\\\"color: rgb(34, 34, 34);\\\">秦始皇统一六国（公元前230年至前221年）是中国历史上划时代的伟大变革。这一事件不仅结束了自春秋战国以来长达500多年的诸侯割据与连年战乱，更在政治、经济、文化等多个维度上，为中国两千多年的封建社会奠定了深厚的根基。其深远的历史意义主要体现在以下几个方面：<\\/span><\\/p><p><strong>1. 建立首个大一统王朝，重塑国家形态<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">秦始皇先后攻灭韩、赵、魏、楚、燕、齐六国，建立了中国历史上第一个统一的多民族专制主义中央集权封建国家。这一创举将“中国”从一个狭小的地域称谓，重塑为大一统王朝的专属代名词，赋予了其完整的国家疆域、政治体系与文明内涵，使“统一”从此成为此后中国历史发展的常态与核心追求。<\\/span><\\/p><p><strong>2. 废除分封推行郡县，确立中央集权体制<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">在政治制度上，秦始皇废除了容易导致地方割据的分封制，在全国范围内全面推行郡县制。他将全国划分为三十六郡，郡下设县，地方长官由朝廷直接任免，实现了中央对地方的垂直、有效管控。同时，在中央确立了三公九卿制度，打破了贵族世袭特权。这套高度集权的国家治理模式，为后世历代王朝所沿袭，奠定了中国古代两千多年政治制度的基本格局。<\\/span><\\/p><p><strong>3. 推行“书同文、车同轨”，铸就中华文化共同体<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">为了消除各地的沟通与流通障碍，秦始皇实施了一系列统一措施。在文化上，他规范并统一文字，将小篆作为官方标准字体，使得政令得以畅通下达，古书典籍得以保存流传，为中华民族形成跨地域的文化共同体和连绵不断的中华文明提供了初始条件。在交通上，规定“车同轨”，修筑以咸阳为中心的驰道和直道，极大提升了军队调度和政令传递的效率，也促进了各地民风文化的交流融合。<\\/span><\\/p><p><strong>4. 统一度量衡与货币，促进全国经济交融<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">在经济领域，秦朝废除了六国旧币，统一使用圆形方孔的“秦半两”钱，并制定了全国统一的尺寸、容量和重量标准。这些举措打破了以往的地域经济壁垒，极大地便利了跨区域的商贸往来与物资流通，客观上促进了统一多元的中国市场的形成，也为国家规范赋税提供了保障。<\\/span><\\/p><p><strong>5. 拓展疆域与开疆拓土，奠定大中国版图基础<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">在巩固内部统一的同时，秦始皇还致力于拓展和稳固边疆。他北击匈奴，连接并修筑了万里长城，保障了中原地区的农业生产与百姓安全；南征百越，修筑灵渠沟通长江与珠江水系，并设立南海、桂林、象郡等行政机构。这些举措不仅扩大了帝国的版图，也促进了华夏区与各民族的整合与交融，为后世“大中国”的地大物博奠定了坚实基础。<\\/span><\\/p><p><span style=\\\"color: rgb(34, 34, 34);\\\">综上所述，秦始皇统一六国的意义远不止于军事上的征服。他通过一系列前所未有的制度重构与文化整合，缔造了真正的“中国”，其开创的大一统格局和制度体系，成为了中华文明生生不息、历经分裂仍能持续重建的核心基石。<\\/span><\\/p>\",\"points\":[5]}],\"rowsQuestions\":[{\"questionid\":19,\"questiontype\":6,\"question\":\"<p>关于秦始皇统一六国的历史事迹，完成下面的问题<\\/p>\",\"questionhtml\":\"\",\"questionlevel\":1,\"questionisparent\":1,\"questionanswer\":\"\",\"points\":[5],\"children\":[{\"questionid\":20,\"questiontype\":1,\"question\":\"<p>最后一个被灭的六国之一是哪个国家？<\\/p>\",\"questionhtml\":[\"赵\",\"齐\",\"燕\",\"楚\"],\"questionlevel\":1,\"questionparent\":19,\"questionanswer\":\"B\"},{\"questionid\":21,\"questiontype\":6,\"question\":\"<p>楚虽三户，亡秦必楚，推断楚国在战国的历史低位如何<\\/p>\",\"questionhtml\":null,\"questionlevel\":1,\"questionparent\":19,\"questionanswer\":\"<p><span style=\\\"color: rgb(34, 34, 34);\\\">“楚虽三户，亡秦必楚”这句出自《史记》的历史名言，不仅是一句充满复仇情绪的谶语，更是对楚国在战国时期独特历史地位的高度概括。结合历史资料，楚国在战国时期的历史地位可以从以下几个核心维度进行推断：<\\/span><\\/p><p><strong>1. 疆域与体量上的“超级大国”<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">楚国是春秋战国时代面积最大的诸侯国，先后统治的土地约占周王朝全部国土的二分之一。凭借“楚地千里”的广阔疆域、庞大的人口以及丰富的物产，楚国在战国七雄中拥有最雄厚的物质基础。这种庞大的体量，使其成为秦国统一天下道路上最难啃的骨头，也是反秦力量最深厚的根基。<\\/span><\\/p><p><strong>2. 政治制度上的“过渡形态”与内部隐患<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">与秦国通过商鞅变法建立起高度集权的郡县制和军功爵制不同，楚国在战国时期依然保留了浓厚的旧贵族色彩。楚国是战国七雄中实行“封君制”最早、封君最多、封地最广的国家，多元的政治结构导致国家权力分散，缺乏如秦国般高效的中央集权体系。这种“贵族专权”的旧体制，使得楚国在战国中后期的国家动员能力和战略执行力上落后于秦国，这也是其最终在军事上败亡的根本原因。<\\/span><\\/p><p><strong>3. 文化层面的“华夏代表”与精神高地<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">楚国虽然曾被中原视为“蛮夷”，但其在战国时期不仅不排斥中原文化，反而以极强的包容力“兼收并蓄”，最终成为东周华夏文化的主要代表。楚文化瑰丽多彩、自由浪漫，孕育了老庄哲学等形而上思辨思想，其文化水平和气魄在当时首屈一指。这种深厚的文化底蕴和强烈的民族认同感，使得楚国在亡国后依然能保持强大的精神凝聚力，为后来的反秦斗争提供了源源不断的动力。<\\/span><\\/p><p><strong>4. 民族融合上的“协和夷夏”先驱<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">楚国在扩张过程中，采取了比中原诸侯更为开明的“混一夷夏”政策。他们不以正统自居，通过武力与怀柔并重的方式，将南方众多土著民族纳入华夏文明圈。这种开放融合的传统，使得楚人在秦末起义时，能够轻易团结东周各国的遗民，成为号令天下的盟主。<\\/span><\\/p><p><strong>5. 历史走向的“终结者与开创者”<br><\\/strong><span style=\\\"color: rgb(34, 34, 34);\\\">“亡秦必楚”最终被历史印证。无论是首义反秦的陈胜（建立“张楚”政权），还是摧毁秦军主力的项羽（建立“西楚”），亦或是最终建立汉朝的刘邦，其核心力量与开国元勋皆出自楚地。楚国虽然在军事上被秦国所灭，但在政治和文化上却完成了对秦朝的“反向征服”。刘邦建立的汉朝，在制度上借鉴了楚国的封君制与郡县制并行经验，在文化上全面复兴了楚文化（如黄老之术、楚辞汉赋）。<\\/span><\\/p><p><span style=\\\"color: rgb(34, 34, 34);\\\">综上所述，楚国在战国时期的历史地位是极其特殊且关键的。它虽然在政治体制的演进上落后于秦国，导致了军事上的覆灭；但凭借其广袤的疆域、深厚的文化底蕴、包容的民族政策以及强大的民族凝聚力，楚国成为了终结暴秦统治的核心力量，并为随后汉朝四百年的大一统格局奠定了坚实的政治与文化基础。中华民族的大一统，楚国功莫大焉。<\\/span><\\/p>\"}]}]}}', '{\"14\":\"C\",\"15\":\"B\",\"16\":\"ABCD\",\"17\":\"AD\",\"18\":\"<p><span style=\\\"color: rgba(0, 0, 0, 0.85); background-color: rgb(255, 255, 255); font-size: 16px;\\\">简述秦始皇统一六国的历史意义<\\/span><\\/p>\",\"20\":\"B\",\"21\":\"<p><span style=\\\"color: rgba(0, 0, 0, 0.85); background-color: rgb(255, 255, 255); font-size: 16px;\\\">楚虽三户，亡秦必楚，推断楚国在战国的历史低位如何<\\/span><\\/p>\"}', '[]', '[]');
