  `examsessionsetting` mediumtext CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `examsessionsign` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `examsessionbasicid` int NOT NULL DEFAULT 0,
  `examsessiontype` int NOT NULL,
  `examsessionpaperid` int(11) UNSIGNED ZEROFILL NOT NULL,
  `examsessionquestion` longtext CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `examsessionuseranswer` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `examsessionstarttime` int NOT NULL DEFAULT 0,
  `examsessiontime` int NOT NULL DEFAULT 0,
  `examsessiontimelist` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `examsessiontoken` varchar(48) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `examsessionfacelist` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `examsessionip` varchar(72) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
